import React, { useState, useEffect } from 'react';

function Admin() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState('events'); // 'events' or 'accounts'
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  // Event form state
  const [events, setEvents] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [eventForm, setEventForm] = useState({
    title: '',
    desc: '',
    month: '',
    day: '',
    type: 'Academic',
    accent: 'border-l-brand-brown',
    textColor: 'text-brand-brown',
    badge: false
  });

  // Account form state
  const [accountForm, setAccountForm] = useState({
    username: '',
    email: '',
    newPassword: '',
    confirmPassword: ''
  });

  const defaultEvents = [
    { id: 1, month: 'JAN', day: '05', title: 'INDUS CUP 2K26', desc: 'Stand a Chance to Win Cash Prizes up to ₹10,00,000', type: 'Sports Fest', accent: 'border-l-orange-500', textColor: 'text-orange-600' },
    { id: 2, month: 'FEB', day: '15', title: 'Indus Hackathon 2025', desc: 'Exhilarating one-day event organized by the CSE Department.', type: 'Technical', accent: 'border-l-blue-500', textColor: 'text-blue-600', badge: true },
    { id: 3, month: 'APR', day: '27', title: 'ISTE State Convention', desc: '26th ISTE Faculty Annual State Convention at Indus.', type: 'Academic', accent: 'border-l-brand-brown', textColor: 'text-brand-brown' },
  ];

  useEffect(() => {
    const savedEvents = localStorage.getItem('indus_events');
    if (savedEvents) {
      setEvents(JSON.parse(savedEvents));
    } else {
      setEvents(defaultEvents);
      localStorage.setItem('indus_events', JSON.stringify(defaultEvents));
    }
  }, []);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === '0000') {
      setIsAuthenticated(true);
      setError('');
    } else {
      setError('Invalid temporary password');
    }
  };

  const saveEventsToStorage = (updatedEvents) => {
    setEvents(updatedEvents);
    localStorage.setItem('indus_events', JSON.stringify(updatedEvents));
  };

  const handleEventSubmit = (e) => {
    e.preventDefault();
    let updatedEvents;
    if (editingId !== null) {
      updatedEvents = events.map(ev => ev.id === editingId ? { ...eventForm, id: editingId } : ev);
      setEditingId(null);
    } else {
      const newEvent = { ...eventForm, id: Date.now() };
      updatedEvents = [...events, newEvent];
    }
    saveEventsToStorage(updatedEvents);
    setSuccess('Event saved successfully!');
    setEventForm({ title: '', desc: '', month: '', day: '', type: 'Academic', accent: 'border-l-brand-brown', textColor: 'text-brand-brown', badge: false });
    setTimeout(() => setSuccess(false), 3000);
  };

  const deleteEvent = (id) => {
    if (window.confirm('Are you sure you want to delete this event?')) {
      const updatedEvents = events.filter(ev => ev.id !== id);
      saveEventsToStorage(updatedEvents);
    }
  };

  const startEdit = (ev) => {
    setEditingId(ev.id);
    setEventForm({ ...ev });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCreateAccount = (e) => {
    e.preventDefault();
    if (accountForm.newPassword !== accountForm.confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    const admins = JSON.parse(localStorage.getItem('admin_accounts') || '[]');
    admins.push({ username: accountForm.username, email: accountForm.email, password: accountForm.newPassword });
    localStorage.setItem('admin_accounts', JSON.stringify(admins));
    setSuccess('Account created successfully!');
    setAccountForm({ username: '', email: '', newPassword: '', confirmPassword: '' });
    setTimeout(() => setSuccess(false), 3000);
  };

  if (!isAuthenticated) {
    return (
      <div className="flex items-center justify-center min-h-[70vh] fade-in">
        <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl border border-gray-100 w-full max-w-lg">
          <div className="text-center mb-10">
            <h2 className="text-4xl font-extrabold text-gray-900 mb-3 tracking-tight">Admin Portal</h2>
            <p className="text-gray-500 font-medium">Authentication required to access management tools</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-8">
            <div>
              <input
                type="password"
                placeholder="Password (0000)"
                className="w-full px-8 py-5 bg-gray-50 border-2 border-gray-100 rounded-3xl focus:outline-none focus:ring-4 focus:ring-brand-brown/10 focus:border-brand-brown transition-all text-center text-3xl tracking-[0.5em] font-black placeholder:tracking-normal placeholder:text-xl placeholder:font-bold"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>
            {error && <p className="text-red-500 text-sm text-center font-bold">{error}</p>}
            <button type="submit" className="w-full py-5 bg-brand-brown text-white rounded-3xl font-extrabold shadow-xl hover:shadow-2xl hover:-translate-y-1 transition-all text-lg uppercase tracking-wider">
              Unlock Terminal
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="fade-in max-w-6xl mx-auto pb-32">
      <header className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-8 border-b-2 border-gray-100 pb-8">
        <div>
          <h1 className="text-5xl font-black text-gray-900 mb-2 tracking-tight">Institutional Management</h1>
          <p className="text-xl text-gray-500 font-medium italic">Welcome to the central control panel</p>
        </div>
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-gray-100">
          <button onClick={() => setActiveTab('events')} className={`px-6 py-3 rounded-xl font-bold transition-all ${activeTab === 'events' ? 'bg-brand-brown text-white shadow-md' : 'text-gray-500 hover:text-brand-brown'}`}>
            Events Manager
          </button>
          <button onClick={() => setActiveTab('accounts')} className={`px-6 py-3 rounded-xl font-bold transition-all ${activeTab === 'accounts' ? 'bg-brand-brown text-white shadow-md' : 'text-gray-500 hover:text-brand-brown'}`}>
            Personnel Admin
          </button>
        </div>
      </header>

      {success && (
        <div className="fixed top-8 right-8 z-[100] p-6 bg-green-500 text-white rounded-3xl shadow-2xl font-bold animate-bounce flex items-center gap-3">
           <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
           {success}
        </div>
      )}

      {activeTab === 'events' ? (
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
          {/* Event Form */}
          <div className="xl:col-span-5">
            <div className="bg-white p-10 rounded-[2.5rem] shadow-xl border border-gray-100 sticky top-8">
              <h2 className="text-2xl font-black text-gray-900 mb-8 border-l-4 border-brand-brown pl-4">{editingId ? 'Edit Event Instance' : 'Provision New Event'}</h2>
              <form onSubmit={handleEventSubmit} className="space-y-6">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-xs font-black text-gray-400 uppercase ml-1">Event Month</label>
                      <input type="text" required placeholder="JAN" maxLength="3" className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold uppercase" value={eventForm.month} onChange={(e) => setEventForm({...eventForm, month: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-black text-gray-400 uppercase ml-1">Event Day</label>
                      <input type="text" required placeholder="01" maxLength="2" className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={eventForm.day} onChange={(e) => setEventForm({...eventForm, day: e.target.value})} />
                    </div>
                 </div>
                 <div className="space-y-2">
                   <label className="text-xs font-black text-gray-400 uppercase ml-1">Event Title</label>
                   <input type="text" required className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={eventForm.title} onChange={(e) => setEventForm({...eventForm, title: e.target.value})} />
                 </div>
                 <div className="space-y-2">
                   <label className="text-xs font-black text-gray-400 uppercase ml-1">Description</label>
                   <textarea rows="3" required className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-medium" value={eventForm.desc} onChange={(e) => setEventForm({...eventForm, desc: e.target.value})} />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-xs font-black text-gray-400 uppercase ml-1">Event Type</label>
                      <select className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={eventForm.type} onChange={(e) => setEventForm({...eventForm, type: e.target.value})}>
                        <option>Academic</option><option>Technical</option><option>Sports Fest</option><option>Cultural</option><option>Placement</option>
                      </select>
                    </div>
                    <div className="flex items-center justify-center pt-6">
                       <label className="flex items-center gap-3 cursor-pointer group">
                         <div className="relative">
                            <input type="checkbox" className="sr-only" checked={eventForm.badge} onChange={(e) => setEventForm({...eventForm, badge: e.target.checked})} />
                            <div className={`w-12 h-6 bg-gray-200 rounded-full transition-colors flex items-center px-1 ${eventForm.badge ? 'bg-blue-600' : ''}`}>
                               <div className={`w-4 h-4 bg-white rounded-full transition-transform ${eventForm.badge ? 'translate-x-6' : ''}`} />
                            </div>
                         </div>
                         <span className="text-sm font-bold text-gray-600 group-hover:text-blue-600 transition-colors">Featured Event</span>
                       </label>
                    </div>
                 </div>
                 <div className="pt-4 flex gap-3">
                   <button type="submit" className="flex-1 py-5 bg-brand-brown text-white rounded-2xl font-black shadow-lg hover:shadow-xl hover:-translate-y-1 transition-all uppercase tracking-widest">{editingId ? 'Update Record' : 'Deploy Event'}</button>
                   {editingId && <button onClick={() => {setEditingId(null); setEventForm({title:'',desc:'',month:'',day:'',type:'Academic',accent:'border-l-brand-brown',textColor:'text-brand-brown',badge:false})}} className="px-6 py-5 bg-gray-100 text-gray-500 rounded-2xl font-black hover:bg-gray-200 transition-all uppercase tracking-widest">Cancel</button>}
                 </div>
              </form>
            </div>
          </div>

          {/* Event List */}
          <div className="xl:col-span-7">
            <h2 className="text-2xl font-black text-gray-900 mb-8 border-l-4 border-brand-brown pl-4 uppercase tracking-tighter">Live Directory</h2>
            <div className="space-y-4">
               {events.map((ev) => (
                 <div key={ev.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-gray-100 flex items-center justify-between group hover:shadow-md transition-all">
                    <div className="flex items-center gap-6">
                       <div className="w-16 h-16 bg-gray-50 rounded-2xl flex flex-col items-center justify-center border border-gray-100">
                          <span className="text-[10px] font-black text-gray-400">{ev.month}</span>
                          <span className="text-2xl font-black text-gray-800 leading-none">{ev.day}</span>
                       </div>
                       <div>
                          <h4 className="text-lg font-black text-gray-900 line-clamp-1">{ev.title}</h4>
                          <p className={`text-[10px] font-extrabold uppercase tracking-widest ${ev.textColor}`}>{ev.type}</p>
                       </div>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => startEdit(ev)} className="w-12 h-12 bg-gray-50 text-gray-400 rounded-xl flex items-center justify-center hover:bg-brand-brown hover:text-white transition-all shadow-sm">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M11 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                       </button>
                       <button onClick={() => deleteEvent(ev.id)} className="w-12 h-12 bg-gray-50 text-gray-400 rounded-xl flex items-center justify-center hover:bg-red-500 hover:text-white transition-all shadow-sm">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                       </button>
                    </div>
                 </div>
               ))}
            </div>
          </div>
        </div>
      ) : (
        /* Account Creation Section */
        <div className="max-w-xl mx-auto">
           <div className="bg-white p-12 rounded-[2.5rem] shadow-xl border border-gray-100">
             <h2 className="text-3xl font-black text-gray-900 mb-8 border-l-6 border-brand-brown pl-6">Register Authorized Personnel</h2>
             <form onSubmit={handleCreateAccount} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-sm font-black text-gray-500 uppercase ml-1">Username / Entity</label>
                  <input type="text" required className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={accountForm.username} onChange={(e) => setAccountForm({...accountForm, username: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-black text-gray-500 uppercase ml-1">Email Address</label>
                  <input type="email" required className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={accountForm.email} onChange={(e) => setAccountForm({...accountForm, email: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-black text-gray-500 uppercase ml-1">Secret Access Key</label>
                  <input type="password" required className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={accountForm.newPassword} onChange={(e) => setAccountForm({...accountForm, newPassword: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-black text-gray-500 uppercase ml-1">Verify Key</label>
                  <input type="password" required className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:border-brand-brown transition-all font-bold" value={accountForm.confirmPassword} onChange={(e) => setAccountForm({...accountForm, confirmPassword: e.target.value})} />
                </div>
                <button type="submit" className="w-full py-5 bg-brand-brown text-white rounded-3xl shadow-xl hover:shadow-2xl hover:-translate-y-1 transition-all text-xl font-black uppercase tracking-widest">Authorize Access</button>
             </form>
           </div>
        </div>
      )}
    </div>
  );
}

